“description”： “通过将主题（基于参考照片）放入新的大气背景，然后叠加音乐 UI 来*创建新场景*的提示。”
“styleTags”： [
“美学编辑”，
“电影”，
“场景合成”，
“玻璃晶态”
        ]
    },
“主题引用”： {
“source”： “[上传的图片]”，
“description”： “仅使用此图像作为拍摄对象面部、头发和外观的参考。*不要*使用其原始背景。
    },
“场景”： {
“背景”： {
“setting”：“公交车上的窗户是悲伤的，烦恼的，是悲伤的”，
“details”： “这是主题必须被放置在的*新*环境中，完全取代了原始背景。”
        },
“主题”： {
“description”： “外貌由'[上传图片]'定义的年轻人。”
“pose”： “他的头轻轻地靠在公交车窗上”，
“focus”： “主体清晰对焦，完全融入新背景。”
        }
    },
“overlayObject”： {
“type”： “浮动玻璃变形音乐播放器 UI”，
“relationshipToEnvironment”： “UI 与公交车窗玻璃**完全齐平并物理连接**到同一平面上，**不浮动**，不是屏幕空间。
“transform”： “UI 与窗口表面匹配的 *完全相同的旋转和透视*。如果窗口倾斜，则 UI 倾斜的方式与正确的透视相同。
“surfaceInteraction”： “通过玻璃进行微妙、逼真的反射和轻微折射，极薄的玻璃成型面板集成到窗户表面中。
“组件”： {
“songTitle”： “失事”，
“artistName”： “想象龙”，
“position”： “安装在框架左中区域的公交车窗玻璃上（不浮动）。”
        }
    },
“技术风格”： {
“aspectRatio”： “1：1”，
“photographyStyle”： “电影般的人像，逼真的合成”，
“相机”： {
“shotType”： “中镜头或中特写”，
“angle”： “视线水平”，
“depthOfField”： “浅，模糊新背景（散景）。”
        },
“照明”： {
“type”： “柔和、环境、喜怒无常”，
“description”： “拍摄对象上的照明*必须匹配*新背景设置的照明（例如，透过公交车窗的雨光、柔和的阴影渐变）。”
        },
“颜色”： {
“palette”： “柔和的电影级调色。”
        }
    },
“音频设备”： {
“type”： “微妙的入耳式无线耳塞”，
“fit”：“自然地坐在双耳中，具有正确逼真的皮肤接触”，
“color”： “哑光黑色或深中性色调”，
“consistencyNote”： “没有电缆，没有笨重的游戏耳机”
    },
“moodReinforcement”： “耳塞暗示悲伤的音乐'Wrecked - Imagine Dragons'是受试者正在听的。
}

